import java.sql.*;
public class TxBug {
    static void transfer(Connection conn, int from, int to, int amount) throws SQLException {
        conn.setAutoCommit(false);
        Statement st = conn.createStatement();
        st.executeUpdate("UPDATE accounts SET bal=bal-" + amount + " WHERE id=" + from);
        st.executeUpdate("UPDATE accounts SET bal=bal+" + amount + " WHERE id=" + to);
        conn.commit();
        // if second update throws, first update is not rolled back
    }
}
